from dataclasses import dataclass
from typing import Optional

@dataclass
class ScorecardTrend:
    msp_name: str
    monthly_scores: list[float]   # oldest first, length ≥ 3

    @property
    def current(self) -> float:
        return self.monthly_scores[-1]

    @property
    def three_month_avg(self) -> float:
        return sum(self.monthly_scores[-3:]) / 3

    @property
    def twelve_month_avg(self) -> Optional[float]:
        if len(self.monthly_scores) < 12:
            return None
        return sum(self.monthly_scores[-12:]) / 12

    def slope(self, window: int = 3) -> float:
        """Simple linear trend slope over the last `window` months.
        Positive → improving. Negative → declining.
        """
        recent = self.monthly_scores[-window:]
        n = len(recent)
        x_mean = (n - 1) / 2
        y_mean = sum(recent) / n
        num = sum((i - x_mean) * (v - y_mean) for i, v in enumerate(recent))
        den = sum((i - x_mean) ** 2 for i in range(n))
        return num / den if den else 0.0

    def alert_summary(self) -> list[str]:
        alerts = []
        if self.current < 60:
            alerts.append("CRITICAL: Current score below 60 — exit criteria met")
        elif self.current < 70:
            alerts.append("WARNING: Current score in RED zone")
        if self.slope() < -2.0:
            alerts.append(f"TREND: Score declining at {self.slope():.1f} pts/month over 3 months")
        red_months = sum(1 for s in self.monthly_scores[-3:] if s < 70)
        if red_months >= 2:
            alerts.append(f"PATTERN: {red_months} of last 3 months in RED")
        return alerts


# Example
trend = ScorecardTrend(
    msp_name="AcmeMSP",
    monthly_scores=[82.0, 80.0, 78.0, 77.0, 74.0, 72.0]
)
print(f"Current: {trend.current}")
print(f"3-month avg: {trend.three_month_avg:.1f}")
print(f"Slope: {trend.slope():.2f} pts/month")
for alert in trend.alert_summary():
    print(f"  {alert}")
# Current: 72.0
# 3-month avg: 74.3
# Slope: -2.50 pts/month
#   TREND: Score declining at -2.5 pts/month over 3 months
